import{_ as a,o as n,c as o,a2 as i}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Install Sovereign as an app","description":"Install a Sovereign instance as a PWA and enable app-like features including push notifications.","frontmatter":{"title":"Install Sovereign as an app","description":"Install a Sovereign instance as a PWA and enable app-like features including push notifications."},"headers":[],"relativePath":"docs/pwa.md","filePath":"guides/pwa.md"}'),t={name:"docs/pwa.md"};function s(r,e,l,p,h,d){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="install-sovereign-as-an-app" tabindex="-1">Install Sovereign as an app <a class="header-anchor" href="#install-sovereign-as-an-app" aria-label="Permalink to &quot;Install Sovereign as an app&quot;">​</a></h1><p>A production Sovereign instance is an installable Progressive Web App (PWA). Installing it gives the workspace its own icon and app window, keeps it close to your other apps, and enables platform features such as background push notifications when the operator and device support them.</p><p>You install a specific <strong>Sovereign instance</strong>, not a global Sovereign app. The icon always opens the instance URL you installed, and your account remains under that instance&#39;s operator and policies.</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><ul><li>Use the instance&#39;s public <code>https://</code> address. Installation, service workers, and Web Push require a secure connection in production.</li><li>Confirm that you can sign in to the instance in the browser.</li><li>Use a current browser and operating-system version.</li><li>For push notifications, the operator must configure Web Push for the instance. If it is not configured, the push controls do not appear.</li></ul><h2 id="install-on-iphone-or-ipad" tabindex="-1">Install on iPhone or iPad <a class="header-anchor" href="#install-on-iphone-or-ipad" aria-label="Permalink to &quot;Install on iPhone or iPad&quot;">​</a></h2><p>Use Safari for the installation flow:</p><ol><li>Open the Sovereign instance URL in <strong>Safari</strong>.</li><li>Sign in and confirm that the workspace loads.</li><li>Tap <strong>Share</strong> in Safari.</li><li>Choose <strong>Add to Home Screen</strong>.</li><li>Review the instance name and tap <strong>Add</strong>.</li><li>Leave Safari and open Sovereign from the new Home Screen icon.</li><li>Confirm that it opens in its own app window rather than a normal browser tab.</li></ol><p>Web Push on iPhone and iPad requires iOS or iPadOS 16.4 or later and an installed Home Screen PWA. Enable notifications from the installed app, not from the original Safari tab.</p><h2 id="install-on-android" tabindex="-1">Install on Android <a class="header-anchor" href="#install-on-android" aria-label="Permalink to &quot;Install on Android&quot;">​</a></h2><p>Use Chrome or another browser that supports PWA installation:</p><ol><li>Open the Sovereign instance URL in the browser.</li><li>Sign in and confirm that the workspace loads.</li><li>Open the browser menu.</li><li>Choose <strong>Install app</strong> or <strong>Add to Home screen</strong>. The wording depends on the browser and device.</li><li>Confirm the installation.</li><li>Open Sovereign from the app launcher or Home Screen icon.</li><li>Confirm that it opens as a standalone app.</li></ol><p>Some Android browsers show an installation prompt automatically. Dismissed prompts can usually be opened again from the browser menu.</p><h2 id="install-on-a-desktop" tabindex="-1">Install on a desktop <a class="header-anchor" href="#install-on-a-desktop" aria-label="Permalink to &quot;Install on a desktop&quot;">​</a></h2><p>Chrome and Edge can install a Sovereign instance on supported desktop systems:</p><ol><li>Open and sign in to the instance.</li><li>Select the install action in the address bar, or open the browser menu and choose <strong>Install Sovereign</strong>.</li><li>Confirm the installation.</li><li>Launch Sovereign from the operating system&#39;s application menu or dock.</li></ol><p>The exact wording and location of the install action depend on the browser.</p><h2 id="enable-push-notifications" tabindex="-1">Enable push notifications <a class="header-anchor" href="#enable-push-notifications" aria-label="Permalink to &quot;Enable push notifications&quot;">​</a></h2><p>Push is opt-in for each device. Installing on one phone or computer does not subscribe your other devices.</p><ol><li>Open the installed Sovereign app on the device you want to subscribe.</li><li>Open <strong>Account</strong> from the workspace.</li><li>Select the <strong>Notifications</strong> tab.</li><li>Under <strong>Push notifications</strong>, select <strong>Enable push notifications</strong>.</li><li>When the operating system or browser asks for permission, choose <strong>Allow</strong>.</li><li>Return to the Notifications page and confirm that it says push notifications are enabled on this device.</li></ol><p>Notifications can now appear even when the app is not open. Selecting a notification opens or focuses the relevant Sovereign page.</p><p>Do not deny the permission prompt as a test. Browsers often require notification permission to be restored manually in site or operating-system settings after it has been denied.</p><h2 id="control-notification-behavior" tabindex="-1">Control notification behavior <a class="header-anchor" href="#control-notification-behavior" aria-label="Permalink to &quot;Control notification behavior&quot;">​</a></h2><p>The <strong>Account → Notifications</strong> page also provides:</p><ul><li><strong>Muted categories:</strong> Discard selected notification categories before they create toasts, bell badges, or push alerts. Security notifications cannot be muted.</li><li><strong>Poll interval:</strong> Control how frequently an open browser checks for new notifications when the instance uses polling.</li><li><strong>Disable push on this device:</strong> Remove the current device&#39;s browser subscription and stop background delivery to it.</li></ul><p>The in-app notification bell continues to work when push is unavailable or not enabled.</p><h2 id="app-like-behavior-and-limits" tabindex="-1">App-like behavior and limits <a class="header-anchor" href="#app-like-behavior-and-limits" aria-label="Permalink to &quot;App-like behavior and limits&quot;">​</a></h2><p>When installed, Sovereign uses a standalone window, mobile safe-area handling, touch-friendly navigation, app shortcuts, and a service worker. If connectivity is lost, the workspace shows an offline state and reloads when the connection returns.</p><p>Sovereign is not fully offline-first. The service worker can show a reliable offline fallback, but apps generally require the instance server for current data, authentication, and mutations. Do not assume that work performed without a connection will be stored or synchronized unless the individual app explicitly documents that behavior.</p><h2 id="updates" tabindex="-1">Updates <a class="header-anchor" href="#updates" aria-label="Permalink to &quot;Updates&quot;">​</a></h2><p>The installed PWA continues to use the operator&#39;s deployed instance. Updates are delivered through that instance rather than an app store. After the operator deploys a new release, close and reopen the app if the update does not appear immediately.</p><p>If an update appears stuck:</p><ol><li>Confirm the device is online.</li><li>Close every window for that Sovereign instance.</li><li>Reopen the installed app.</li><li>If the problem remains, remove and reinstall the PWA or clear that instance&#39;s website data. Clearing website data signs you out and removes the device&#39;s push subscription.</li></ol><h2 id="troubleshooting-installation" tabindex="-1">Troubleshooting installation <a class="header-anchor" href="#troubleshooting-installation" aria-label="Permalink to &quot;Troubleshooting installation&quot;">​</a></h2><h3 id="the-install-action-does-not-appear" tabindex="-1">The install action does not appear <a class="header-anchor" href="#the-install-action-does-not-appear" aria-label="Permalink to &quot;The install action does not appear&quot;">​</a></h3><ul><li>Confirm the URL uses HTTPS and the instance loaded without certificate errors.</li><li>Reload after the first successful visit so the service worker can register.</li><li>Use Safari on iPhone or iPad and Chrome or Edge on supported Android and desktop systems.</li><li>Ask the operator whether the production PWA assets and manifest are being served correctly.</li></ul><h3 id="push-controls-do-not-appear" tabindex="-1">Push controls do not appear <a class="header-anchor" href="#push-controls-do-not-appear" aria-label="Permalink to &quot;Push controls do not appear&quot;">​</a></h3><p>The operator has probably not configured VAPID keys. The in-app bell remains available. Contact the instance operator if background push is expected.</p><h3 id="push-permission-was-denied" tabindex="-1">Push permission was denied <a class="header-anchor" href="#push-permission-was-denied" aria-label="Permalink to &quot;Push permission was denied&quot;">​</a></h3><p>Open the device&#39;s notification settings or the browser&#39;s site settings for the instance and restore permission. Then return to <strong>Account → Notifications</strong> and enable push again.</p><h3 id="notifications-are-enabled-but-do-not-arrive" tabindex="-1">Notifications are enabled but do not arrive <a class="header-anchor" href="#notifications-are-enabled-but-do-not-arrive" aria-label="Permalink to &quot;Notifications are enabled but do not arrive&quot;">​</a></h3><ul><li>Confirm notifications are allowed for the installed app at the OS level.</li><li>Confirm the relevant category is not muted.</li><li>On iOS, confirm the app was installed from Safari and opened from the Home Screen before subscribing.</li><li>Ask the operator to verify VAPID configuration and push-delivery logs.</li><li>Disable and re-enable push to replace a stale device subscription.</li></ul><h2 id="operator-requirements" tabindex="-1">Operator requirements <a class="header-anchor" href="#operator-requirements" aria-label="Permalink to &quot;Operator requirements&quot;">​</a></h2><p>Operators should review <a href="/self-hosting.html#web-push-notifications-rfc-0016">Web Push configuration in the self-hosting guide</a>. Production push requires a stable VAPID key pair and a real <code>VAPID_CONTACT</code> URI. Rotating the key pair invalidates existing subscriptions and requires users to subscribe again.</p><p>For release testing on physical devices, use the <a href="/pwa-real-device-testing.html">real-device PWA testing guide</a>.</p>',45)])])}const f=a(t,[["render",s]]);export{u as __pageData,f as default};
